// rStep3 removes final case endings with R1 check.
func (s *SerbianStemmer) rStep3() bool {
	s.Ket = s.Cursor
	if s.FindAmongB(serbianA3) == 0 {
		return false
	}
	s.Bra = s.Cursor
	if !s.rR1() {
		return false
	}
	s.SliceFromStr("")
	return true
}

// Stem performs Serbian stemming.
func (s *SerbianStemmer) Stem() bool {
	s.rCyrToLat()
	s.rPrelude()
	s.rMarkRegions()
	s.LimitBackward = s.Cursor
	s.Cursor = s.Limit
	v4 := s.Limit - s.Cursor
	s.rStep1()
	s.Cursor = s.Limit - v4
	v5 := s.Limit - s.Cursor
	lab0:
	for {
		lab1:
		for {
			v6 := s.Limit - s.Cursor
			lab2:
			for {
				if !s.rStep2() {
					break lab2
				}
				break lab1
			}
			s.Cursor = s.Limit - v6
			if !s.rStep3() {
				break lab0
			}
			break lab1
		}
		break lab0
	}
	s.Cursor = s.Limit - v5
	s.Cursor = s.LimitBackward
	return true
}
